1	// ── Lissajous Curve Mathematics ─────────────────────────────────────
2	// Canonical source for the Lightfast logo curve and all derived patterns.
3	// Parametric form: x(t) = sin(a·t + δ), y(t) = sin(b·t)
4	
5	/** Default logo curve parameters: a=3, b=2, δ=π/2 */
6	export const LOGO_CURVE = { a: 3, b: 2, delta: Math.PI / 2 } as const;
7	
8	/** All 9 footer/brand patterns */
9	export const LISSAJOUS_PATTERNS = [
10	  { name: "circle", a: 1, b: 1, delta: Math.PI / 2 },
11	  { name: "figure8", a: 1, b: 2, delta: Math.PI / 2 },
12	  { name: "pretzel", a: 3, b: 2, delta: Math.PI / 2 },
13	  { name: "bow", a: 2, b: 3, delta: Math.PI / 2 },
14	  { name: "knot", a: 3, b: 4, delta: Math.PI / 2 },
15	  { name: "star", a: 5, b: 4, delta: Math.PI / 2 },
16	  { name: "wave", a: 1, b: 3, delta: Math.PI / 4 },
17	  { name: "infinity", a: 2, b: 1, delta: Math.PI / 2 },
18	  { name: "clover", a: 3, b: 1, delta: Math.PI / 2 },
19	] as const;
20	
21	/**
22	 * Generate an SVG path for a Lissajous curve centered in a square canvas.
23	 * Used by: Logo component (Remotion), OG images (Satori), footer (React).
24	 *
25	 * @param size - Canvas width/height in px
26	 * @param padding - Fraction of size reserved as padding (0–0.5)
27	 * @param a - x-frequency (default: LOGO_CURVE.a)
28	 * @param b - y-frequency (default: LOGO_CURVE.b)
29	 * @param delta - phase shift (default: LOGO_CURVE.delta)
30	 * @param steps - number of sample points (default: 512)
31	 */
32	export function lissajousPath(
33	  size: number,
34	  padding: number,
35	  a: number = LOGO_CURVE.a,
36	  b: number = LOGO_CURVE.b,
37	  delta: number = LOGO_CURVE.delta,
38	  steps: number = 512,
39	): string {
40	  const center = size / 2;
41	  const radius = size * (0.5 - padding);
42	
43	  let d = "";
44	  for (let i = 0; i <= steps; i++) {
45	    const t = (i / steps) * 2 * Math.PI;
46	    const x = center + radius * Math.sin(a * t + delta);
47	    const y = center + radius * Math.sin(b * t);
48	    d += `${i === 0 ? "M" : "L"}${x.toFixed(2)},${y.toFixed(2)}`;
49	  }
50	  return `${d} Z`;
51	}
52	
53	/**
54	 * Generate an SVG path for a Lissajous curve in a normalized viewBox (0–100).
55	 * Used by: footer patterns.
56	 */
57	export function lissajousPathNormalized(
58	  a: number,
59	  b: number,
60	  delta: number,
61	  points = 500,
62	  padding = 10,
63	): string {
64	  const size = 100 - padding * 2;
65	  const pts: string[] = [];
66	  for (let i = 0; i <= points; i++) {
67	    const t = (i / points) * 2 * Math.PI;
68	    const x = padding + ((Math.sin(a * t + delta) + 1) / 2) * size;
69	    const y = padding + ((Math.sin(b * t) + 1) / 2) * size;
70	    pts.push(`${i === 0 ? "M" : "L"} ${x.toFixed(2)} ${y.toFixed(2)}`);
71	  }
72	  return pts.join(" ");
73	}
74	
75	/**
76	 * Generate raw [x,y] points for a Lissajous curve.
77	 * Used by: landing-hero logo animation (needs individual points for trail effect).
78	 */
